import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { apiClient } from "@/App";
import { toast } from "sonner";
import { Plus, FileText, Calendar } from "lucide-react";
import jsPDF from "jspdf";

const ExamsPage = () => {
  const [exams, setExams] = useState([]);
  const [loading, setLoading] = useState(true);
  const [dialogOpen, setDialogOpen] = useState(false);

  const [formData, setFormData] = useState({
    name: "",
    class_name: "",
    year_of_study: "",
    term: "Term 1",
    exam_number: "Exam 1",
    academic_year: new Date().getFullYear().toString(),
    exam_date: ""
  });

  const update = (key, value) =>
    setFormData((prev) => ({ ...prev, [key]: value }));

  const kenyaClasses = [
    "PP1","PP2","Grade 1","Grade 2","Grade 3","Grade 4","Grade 5","Grade 6",
    "Grade 7","Grade 8","Grade 9","Grade 10","Grade 11","Grade 12"
  ];

  const collegeYears = ["Year 1","Year 2","Year 3","Year 4","Year 5","Year 6"];

  useEffect(() => {
    fetchExams();
  }, []);

  const fetchExams = async () => {
    try {
      const res = await apiClient.get("/exams");
      setExams(Array.isArray(res.data) ? res.data : []);
    } catch {
      toast.error("Failed to fetch exams");
      setExams([]);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await apiClient.post("/exams", formData);
      toast.success("Exam created successfully");
      setDialogOpen(false);
      fetchExams();
    } catch (error) {
      toast.error(error?.response?.data?.detail || "Failed to create exam");
    }
  };

  const generateReport = () => {
    const doc = new jsPDF();
    doc.text("Exam Report", 20, 20);

    let y = 40;

    exams.forEach((exam, i) => {
      doc.text(`${i + 1}. ${exam?.name ?? "Unnamed"}`, 20, y);
      y += 10;
    });

    doc.save("exam-report.pdf");
  };

  const groupedExams = exams.reduce((acc, exam) => {
    const key = `${exam?.academic_year || "Unknown"}-${exam?.term || "Term"}`;
    acc[key] = acc[key] || [];
    acc[key].push(exam);
    return acc;
  }, {});

  if (loading) {
    return <div className="p-6 text-slate-400">Loading...</div>;
  }

  return (
    <div className="space-y-6">

      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-bold text-white">Exams</h2>
          <p className="text-slate-400">Manage assessments</p>
        </div>

        <div className="flex gap-2">
          <Button onClick={generateReport} variant="outline">
            <FileText className="w-4 h-4 mr-2" />
            Report
          </Button>

          <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
            <DialogTrigger asChild>
              <Button>
                <Plus className="w-4 h-4 mr-2" />
                Create
              </Button>
            </DialogTrigger>

            <DialogContent>
              <DialogHeader>
                <DialogTitle>Create Exam</DialogTitle>
              </DialogHeader>

              <form onSubmit={handleSubmit} className="space-y-4">

                <div>
                  <Label htmlFor="exam_name">Exam Name</Label>
                  <Input
                    id="exam_name"
                    name="exam_name"
                    value={formData.name}
                    onChange={(e) => update("name", e.target.value)}
                    required
                  />
                </div>

                <div className="grid grid-cols-2 gap-3">

                  <div>
                    <Label htmlFor="class_name">Class</Label>
                    <Select
                      value={formData.class_name}
                      onValueChange={(v) => update("class_name", v)}
                    >
                      <SelectTrigger id="class_name">
                        <SelectValue placeholder="Class" />
                      </SelectTrigger>
                      <SelectContent>
                        {kenyaClasses.map((c) => (
                          <SelectItem key={c} value={c}>{c}</SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>

                  <div>
                    <Label htmlFor="year">Year</Label>
                    <Select
                      value={formData.year_of_study}
                      onValueChange={(v) => update("year_of_study", v)}
                    >
                      <SelectTrigger id="year">
                        <SelectValue placeholder="Year" />
                      </SelectTrigger>
                      <SelectContent>
                        {collegeYears.map((y) => (
                          <SelectItem key={y} value={y}>{y}</SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>

                </div>

                <div>
                  <Label htmlFor="exam_date">Exam Date</Label>
                  <Input
                    id="exam_date"
                    name="exam_date"
                    type="date"
                    value={formData.exam_date}
                    onChange={(e) => update("exam_date", e.target.value)}
                    required
                  />
                </div>

                <Button type="submit" className="w-full">
                  Save
                </Button>

              </form>
            </DialogContent>
          </Dialog>

        </div>
      </div>

      <div className="space-y-4">
        {Object.entries(groupedExams).map(([key, list]) => (
          <Card key={key}>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Calendar className="w-4 h-4" />
                {key}
              </CardTitle>
            </CardHeader>

            <CardContent>
              {list.map((exam, i) => (
                <div key={exam?.id || i} className="p-3 border rounded mb-2">
                  {exam?.name}
                </div>
              ))}
            </CardContent>
          </Card>
        ))}
      </div>

    </div>
  );
};

export default ExamsPage;
